SELECT count(*) FROM company_type, movie_companies, company_name, title, movie_info, info_type, kind_type, cast_info, movie_keyword WHERE movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id;